import{_ as s,c as i,o as a,a2 as e}from"./chunks/framework.DwDoyBw8.js";const E=JSON.parse('{"title":"SVG 滤镜实现图片故障动画","description":"","frontmatter":{},"headers":[],"relativePath":"CSS/效果提升/svg滤镜.md","filePath":"learn/CSS/效果提升/svg滤镜.md","lastUpdated":1730198863000}'),t={name:"CSS/效果提升/svg滤镜.md"},l=e(`<h1 id="svg-滤镜实现图片故障动画" tabindex="-1">SVG 滤镜实现图片故障动画 <a class="header-anchor" href="#svg-滤镜实现图片故障动画" aria-label="Permalink to &quot;SVG 滤镜实现图片故障动画&quot;">​</a></h1><p>svg 有很多滤镜效果，可以前往 <a href="https://yoksel.github.io/svg-filters/#/" target="_blank" rel="noreferrer">SVG Filter</a> 网站自主搭配查看效果。想要实现滤镜效果，需要用到 湍流滤镜和置换滤镜。</p><p>湍流滤镜用到了柏林噪声算法，该算法用于生成随机且自然的纹理，如纸张的褶皱、物体粗糙表面等。</p><p>置换滤镜可以让turbulence滤镜生成的纹理置换到其他图形或文字上，实现故障效果。</p><h2 id="搭配" tabindex="-1">搭配 <a class="header-anchor" href="#搭配" aria-label="Permalink to &quot;搭配&quot;">​</a></h2><p>前往上方链接，找到 <code>feTurbulence</code> 湍流滤镜和 <code>feDisplacementMap</code> 置换滤镜搭配使用，注意放置的顺序，置换滤镜需要放在最后。配置好后右侧效果图会发生相应的样式变化：</p><p><img src="https://pic.imgdb.cn/item/67209d65d29ded1a8c121d68.png" alt="初始效果"></p><p>可以看到图中左侧部分有很多配置的参数，下面挑几个重要的参数进行说明：</p><ul><li><code>feTurbulence</code><ol><li><code>type</code> 置换滤镜的置换类型，可选 <code>turbulence</code> 湍流和 <code>fractalNoise</code> ，二者会有噪声的区别。选择 <code>turbulence</code> 躁点更尖锐，选择 <code>fractalNoise</code> 躁点更柔和。下面来两张效果图对比一下： <img src="https://pic.imgdb.cn/item/67209fcdd29ded1a8c143eb3.png" alt="turbulence"><img src="https://pic.imgdb.cn/item/67209fe9d29ded1a8c145400.png" alt="fractalNoise"></li><li><code>baseFrequency</code> 置换滤镜的频率，频率有两个方向，左侧代表横向，右侧代表纵向。数值越小噪声越小，数值越大噪声越大。噪声越小效果会呈一条直线，噪声越大会有很多躁点。下面来两张效果图对比一下： <img src="https://pic.imgdb.cn/item/6720a0bed29ded1a8c152b65.png" alt="0，0"><img src="https://pic.imgdb.cn/item/6720a0dcd29ded1a8c154ec0.png" alt="1，1"></li><li><code>numOctaves</code> 置换滤镜的躁点数量，数值越大躁点越多</li></ol></li><li><code>feDisplacementMap</code><ol><li><code>scale</code> 置换滤镜的放大倍率，数值越大柏林噪声对其影响越明显，数值越小柏林噪声对其影响越小，如果设为0则完全无影响。下面来两张效果图对比一下： <img src="https://pic.imgdb.cn/item/6720a1ced29ded1a8c162a48.png" alt="scale为0"><img src="https://pic.imgdb.cn/item/6720a1ebd29ded1a8c16411b.png" alt="scale为30"></li></ol></li></ul><p>搭配好之后，效果图下方会生成相应的代码，复制到自己的项目中即可。</p><h2 id="实现" tabindex="-1">实现 <a class="header-anchor" href="#实现" aria-label="Permalink to &quot;实现&quot;">​</a></h2><h3 id="基本效果" tabindex="-1">基本效果 <a class="header-anchor" href="#基本效果" aria-label="Permalink to &quot;基本效果&quot;">​</a></h3><p>新建一个 <code>.vue</code> 组件，放置一个 <code>img</code> 标签。想要使用前面搭配好的滤镜效果，需要用到 <code>svg</code> 标签包裹着 <code>defs</code> 标签，然后把 <code>copy</code> 的代码放到 <code>defs</code> 标签内。代码如下所示：</p><div class="language-html vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">html</span><pre class="shiki shiki-themes github-light github-dark vp-code"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&lt;</span><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">img</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> src</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;./xxx.jpg&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> /&gt;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&lt;</span><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">svg</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> style</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;display: none;&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&gt;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    &lt;</span><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">defs</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&gt;</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">        &lt;!-- 复制的代码 --&gt;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    &lt;/</span><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">defs</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&gt;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&lt;/</span><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">svg</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&gt;</span></span></code></pre></div><p>然后让 <code>img</code> 使用该效果。由于是 <code>svg</code> 的滤镜效果，因此使用 <code>url</code> ，id 为复制过来 <code>filter</code> 标签的 id，可自行更改。</p><div class="language-css vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">css</span><pre class="shiki shiki-themes github-light github-dark vp-code"><code><span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">img</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> {</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">    display</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">block</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">;</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">    width</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">300</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">px</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">;</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">    filter</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">url</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">#filter</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">);</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div><p>此时刷新查看，能够看到图片出现故障效果，只不过没有动画。</p><h3 id="动画添加" tabindex="-1">动画添加 <a class="header-anchor" href="#动画添加" aria-label="Permalink to &quot;动画添加&quot;">​</a></h3><p>想要实现动画效果，无外乎就是改变 <code>feTurbulence</code> 滤镜的 <code>baseFrequency</code> 参数，修改产生的躁点频率。现在有一个问题，如何修改？它不是 <code>CSS</code> 属性，是元素属性，无法用到 <code>transition</code> 过渡。</p><p>有一个第三方库 <code>gsap</code> 可以实现这个功能，GSAP（GreenSock Animation Platform）是一个JavaScript 动画库，提供了丰富的API来创建平滑、高性能的动画效果。下面来看看基本使用：</p><ol><li><p>安装GSAP</p><ul><li>CDN引入：<div class="language-html vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">html</span><pre class="shiki shiki-themes github-light github-dark vp-code"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&lt;</span><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">script</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> src</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;https://cdnjs.cloudflare.com/ajax/libs/gsap/3.9.1/gsap.min.js&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&gt;&lt;/</span><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">script</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&gt;</span></span></code></pre></div></li><li>npm引入：<div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">npm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> gsap</span></span></code></pre></div></li></ul></li><li><p>基本动画</p><p>GSAP提供了几种基本的动画函数：</p><ul><li>gsap.to()：最常用的动画类型，从当前状态开始动画到指定状态。</li><li>gsap.from()：与gsap.to()相反，从指定状态动画到当前状态。</li><li>gsap.fromTo()：可以自定义开始和结束状态。</li><li>gsap.set()：立即设置属性，没有动画效果。</li></ul></li><li><p>时间轴（Timeline） GSAP的时间轴功能允许你将多个动画组合在一起，并精确控制它们的执行顺序。以下是一个使用时间轴的示例：</p></li></ol><p>javascript const timeline = gsap.timeline(); timeline .to(&quot;#box1&quot;, { x: 300, duration: 1 }) .to(&quot;#box2&quot;, { x: 300, duration: 1 }) .to(&quot;#box3&quot;, { x: 300, duration: 1 }); 在这个例子中，三个元素将依次向右移动300px 。</p><ol start="4"><li><p>插件和功能模块 GSAP提供了许多插件，如ScrollTrigger、Draggable等，这些插件可以通过npm安装并注册到GSAP中使用 。</p></li><li><p>控制动画 GSAP允许你在运行时动态控制动画，例如暂停、恢复、反转等：</p></li></ol><p>javascript let tween = gsap.to(&quot;#box&quot;, { x: 100, duration: 1 }); // 播放动画 tween.play(); // 暂停动画 tween.pause(); // 恢复动画 tween.resume(); // 反转动画 tween.reverse(); 这些方法提供了对动画的细粒度控制 。</p>`,24),p=[l];function n(h,d,c,o,k,r){return a(),i("div",null,p)}const u=s(t,[["render",n]]);export{E as __pageData,u as default};
